mapper.update:
update sign_record
set sign_in_time=#{signInTime}, sign_out_time=#{signOutTime},
    sign_in_status=#{signInStatus}, sign_out_status=#{signOutStatus}
where sid=#{sid}

mapper.select:
select count(*)
from sign_record sr
where sr.uid = #{uid}
  and YEAR(sr.sign_in_time) = #{year}
  and MONTH(sr.sign_in_time) = #{month}
